    T=set()
    if T_set!=set():
        T=T_set.copy()
    removed=set()
    risk_edges=set()    


    infected_over_time=[]
    sets=[suceptible,infected,T]
    
    #-------------------------------
    #---Spread model----------------
    #-------------------------------
    if early_stop[0]: 
        t=100000
    for time in range(t):
        if early_stop[0] and (len(infected)/n)*100  >=early_stop[1]: 
            if displ>=1: print("stopping")
            t=time
            break
        sets=[suceptible,infected,T]
        infected_over_time.append(len(infected))

        if len(risk_edges)>0 or time==0:
            if displ>=3:show(n=n,edges=edges,sets=sets,layout=layout) #; print("display")          

            # Determine which edges are adjacent to infected nodes
            risk_edges.clear()
            for edge in edges:
                (i,j)=edge
                if i in infected and j in suceptible :
                    risk_edges.add(edge)
                if i in infected and j in infected :
                    removed.add(edge)
            
            if len(removed)>0:
                for edge in removed:
                    edges.remove(edge)
                removed.clear()    
                
            for inf_edge in risk_edges:
                (i, j) = inf_edge
                if j in suceptible:
                    if np.random.uniform(0,1)<=spread:
                        infected.add(j)                   
                        suceptible.discard(j)
            
    return edges, list(sets), infected_over_time, t

